import React, { useState, useEffect } from 'react';

const EventManage = () => {
  const [events, setEvents] = useState([]);

  useEffect(() => {
    const fetchEvents = async () => {
      const response = await fetch('http://localhost:8000/event/get');
      const data = await response.json();
      setEvents(data);
    };
    fetchEvents();
  }, []);

  const filterEventsByState = (state) => {
    return events.filter(event => event.event_state === state);
  };

  return (
    <div>
      <h2>Draftイbytes:\xe3\x83bytes:\x99ント</h2>
      {filterEventsByState('draft').map((event) => (
        <div key={event.event_id}>{event.event_name}</div>
      ))}
      <h2>Openイbytes:\xe3\x83bytes:\x99ント</h2>
      {filterEventsByState('open').map((event) => (
        <div key={event.event_id}>{event.event_name}</div>
      ))}
      <h2>Closeイbytes:\xe3\x83bytes:\x99ント</h2>
      {filterEventsByState('close').map((event) => (
        <div key={event.event_id}>{event.event_name}</div>
      ))}
    </div>
  );
};

export default EventManage;
